921	postgres	INSERT	support_tickets	32	Record created	\N	{"id": 32, "status": "solved", "line_id": 78, "user_id": 1, "client_id": 16, "created_at": "2026-01-29T11:19:35.456007+04:00", "updated_at": "2026-01-29T11:19:35.456007+04:00", "category_id": 4, "reported_at": "2025-12-16T10:15:00+04:00", "resolved_at": "2025-12-16T11:19:00+04:00", "contact_name": "Дмитрий", "support_line": 1, "work_started_at": null, "total_work_minutes": 0, "problem_description": "\\"Вы вчера дали общую выгрузку за 02.12. с линии минипаков\\nно там было три номенклатуры.\\nБудем с контуровцами опять искать ошибку и надо знать точное количество по каждой из трех.\\n\\nЯ прикладываю ДЖИТИНЫ.\\n04660302991251 (Влажные салфетки Delicare Мини Семейные Алое Вера 8шт)\\n04660302991282 (Влажные салфетки Delicare Мини Семейные Белый чай 8шт)\\n04660302991244 (Влажные салфетки DEFANCE Medis Мини Антибактериальные 8шт)\\n\\n\\nЭто не срочно, но сделайте пожалуйста. \\n\\nЕще сообщите руководству, что компания Медителл/Русвата в лице Дмитрия отнимает у вас много рабочего времени! \\nЯ у вашего руководства просил нам дать програмку, которая бы показывала нам сколько кодов в базе.\\"\\n", "solution_description": "Сделал выгрузку за 02.12 по трем gtin по отдельности\\n"}	2026-01-29 11:19:35.456007+04	\N	\N
