924	postgres	INSERT	support_tickets	35	Record created	\N	{"id": 35, "status": "solved", "line_id": 77, "user_id": 1, "client_id": 16, "created_at": "2026-01-29T11:23:40.808292+04:00", "updated_at": "2026-01-29T11:23:40.808292+04:00", "category_id": 3, "reported_at": "2025-12-18T09:00:00+04:00", "resolved_at": "2025-12-18T09:20:00+04:00", "contact_name": "Евгений Варламов", "support_line": 1, "work_started_at": null, "total_work_minutes": 0, "problem_description": "Блики на плёнке из-за чего код плохо считывается. \\n", "solution_description": "Сообщил, что более продвинутый сканер не решит проблему, что в сетях могут быть проблемы если у них недорогие сканеры и не смогут считать. Чтобы наша камера лучше считывала договорились подключиться посмотреть, что можно сделать. Но в первую очередь нужно решать вопрос с плёнкой. МВВ должен сообщить об этом Русвате, чтобы они передали это технологам, которые не хотят менять плёнку\\n"}	2026-01-29 11:23:40.808292+04	\N	\N
